import { useEffect, useState } from "react";
import socket from "../socket";
import confetti from "canvas-confetti";
import "./GameStyle.css";

function Player() {
  const avatars = [
    "🐵","🦊","🐼","🐯","🦁",
    "🐸","🐧","🐰","🐨","🐶",
    "🐱","🐷","🐙","🦄","🐲"
  ];

  const [name, setName] = useState("");
  const [gamePin, setGamePin] = useState("");
  const [avatar, setAvatar] = useState("🐵");
  const [joined, setJoined] = useState(false);

  const [question, setQuestion] = useState(null);
  const [leaderboard, setLeaderboard] = useState([]);

  const [answered, setAnswered] = useState(false);
  const [answerResult, setAnswerResult] = useState(null);
  const [gameOver, setGameOver] = useState(false);

  const [timeLeft, setTimeLeft] = useState(25);

  useEffect(() => {
    socket.on("nextQuestion", (data) => {
      setQuestion(data.question);
      setTimeLeft(data.timeLimit || 25);
      setAnswered(false);
      setAnswerResult(null);
    });

    socket.on("answerResult", (data) => {
      setAnswerResult(data);
      setAnswered(true);
    });

    socket.on("leaderboardUpdated", (data) => {
      setLeaderboard(data || []);
    });

    socket.on("gameOver", (data) => {
      setLeaderboard(data || []);
      setGameOver(true);

      confetti({ particleCount: 200, spread: 100 });
    });

    return () => {
      socket.off("nextQuestion");
      socket.off("answerResult");
      socket.off("leaderboardUpdated");
      socket.off("gameOver");
    };
  }, []);

  useEffect(() => {
    if (!question || answered) return;

    if (timeLeft <= 0) {
      setAnswered(true);
      return;
    }

    const timer = setTimeout(() => setTimeLeft(timeLeft - 1), 1000);
    return () => clearTimeout(timer);
  }, [timeLeft, question, answered]);

  const joinGame = () => {
    socket.emit("joinGame", {
      gamePin,
      name,
      avatar, // ✅ FIXED
    });

    setJoined(true);
  };

  const answer = (opt) => {
    if (answered) return;

    socket.emit("answer", {
      gamePin,
      correct: opt === question.answer,
    });
  };

  // 🎯 JOIN SCREEN
  if (!joined) {
    return (
      <div className="login-bg">
        <h1 className="login-logo">Unpaid Education</h1>

        <div className="login-card">
          <input
            placeholder="Game PIN"
            value={gamePin}
            onChange={(e) => setGamePin(e.target.value)}
          />

          <input
            placeholder="Nickname"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />

          <h3>Select Avatar</h3>

          <div className="avatar-grid">
            {avatars.map((av, i) => (
              <button
                key={i}
                type="button"  // ✅ VERY IMPORTANT FIX
                className={avatar === av ? "avatar active-avatar" : "avatar"}
                onClick={() => setAvatar(av)}
              >
                {av}
              </button>
            ))}
          </div>

          <button onClick={joinGame}>Enter</button>
        </div>
      </div>
    );
  }

  if (gameOver) {
    return (
      <div className="leaderboard-bg">
        <h1>🏆 Final Leaderboard</h1>

        {leaderboard.map((p, i) => (
          <h2 key={i}>
            {p.avatar} {p.name} - {p.score}
          </h2>
        ))}
      </div>
    );
  }

  if (answered) {
    return (
      <div className="result-bg">
        {answerResult?.correct ? (
          <h1 className="correct">✅ Correct</h1>
        ) : (
          <h1 className="wrong">❌ Wrong</h1>
        )}
        <p>Waiting...</p>
      </div>
    );
  }

  return (
    <div className="question-bg">
      <h2>Time: {timeLeft}</h2>

      <h1>{question?.question}</h1>

      {(question?.options || []).map((opt, i) => (
        <button key={i} onClick={() => answer(opt)} className="answer-btn">
          {opt}
        </button>
      ))}
    </div>
  );
}

export default Player;
